CREATE TABLE user (id BIGINT PRIMARY KEY AUTO_INCREMENT, username VARCHAR(50) NOT NULL UNIQUE, password VARCHAR(255) NOT NULL, role VARCHAR(20) DEFAULT 'USER', email VARCHAR(100), created_at DATETIME DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE company (id BIGINT PRIMARY KEY AUTO_INCREMENT, name VARCHAR(100) NOT NULL, industry VARCHAR(100), city VARCHAR(50), scale VARCHAR(50), website VARCHAR(255), created_at DATETIME NOT NULL);
CREATE TABLE job (id BIGINT PRIMARY KEY AUTO_INCREMENT, company_id BIGINT, title VARCHAR(100) NOT NULL, city VARCHAR(50), experience VARCHAR(50), education VARCHAR(50), skills VARCHAR(500), FOREIGN KEY (company_id) REFERENCES company(id));
CREATE TABLE resume (id BIGINT PRIMARY KEY AUTO_INCREMENT, user_id BIGINT NOT NULL, name VARCHAR(50), education VARCHAR(50), experience_years INT, skills VARCHAR(500), FOREIGN KEY (user_id) REFERENCES user(id));
CREATE TABLE job_application (id BIGINT PRIMARY KEY AUTO_INCREMENT, user_id BIGINT NOT NULL, job_id BIGINT NOT NULL, status VARCHAR(20) DEFAULT 'PENDING', FOREIGN KEY (user_id) REFERENCES user(id), FOREIGN KEY (job_id) REFERENCES job(id));
CREATE TABLE job_favorite (id BIGINT PRIMARY KEY AUTO_INCREMENT, user_id BIGINT NOT NULL, job_id BIGINT NOT NULL, FOREIGN KEY (user_id) REFERENCES user(id), FOREIGN KEY (job_id) REFERENCES job(id));
CREATE TABLE crawl_task (id BIGINT PRIMARY KEY AUTO_INCREMENT, source_website VARCHAR(100), keyword VARCHAR(100), status VARCHAR(20) DEFAULT 'PENDING', created_at DATETIME NOT NULL);
CREATE TABLE system_log (id BIGINT PRIMARY KEY AUTO_INCREMENT, username VARCHAR(50), operation VARCHAR(100), created_at DATETIME NOT NULL);
CREATE TABLE search_history (id BIGINT PRIMARY KEY AUTO_INCREMENT, user_id BIGINT NOT NULL, keyword VARCHAR(200), FOREIGN KEY (user_id) REFERENCES user(id));